import { useEffect, useState } from "react";

const SIZE = 10;

function move(game) {
  const [r, c] = game.snake[0];

  const head = [
    r + game.direction[0],
    c + game.direction[1],
  ];

  const snake = [head, ...game.snake];

  if (head[0] === game.food[0] && head[1] === game.food[1]) {
    return {
      ...game,
      snake,
      food: [Math.floor(Math.random() * SIZE), Math.floor(Math.random() * SIZE)],
    };
  }

  snake.pop();

  return {
    ...game,
    snake,
  };
}

export default function Snake() {
  const [game, setGame] = useState({
    snake: [[5, 5]],
    food: [2, 2],
    direction: [0, 1],
  });

  useEffect(() => {
    const timer = setInterval(() => {
      setGame(move);
    }, 300);

    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    function key(e) {
      if (e.key === "ArrowUp") {
        setGame(g => ({ ...g, direction: [-1, 0] }));
      }

      if (e.key === "ArrowDown") {
        setGame(g => ({ ...g, direction: [1, 0] }));
      }

      if (e.key === "ArrowLeft") {
        setGame(g => ({ ...g, direction: [0, -1] }));
      }

      if (e.key === "ArrowRight") {
        setGame(g => ({ ...g, direction: [0, 1] }));
      }
    }

    window.addEventListener("keydown", key);
    return () => window.removeEventListener("keydown", key);
  }, []);

  return (
    <main>
      <h1>🐍 Snake</h1>

      <table>
        <tbody>
          {Array.from({ length: SIZE }, (_, r) => (
            <tr key={r}>
              {Array.from({ length: SIZE }, (_, c) => (
                <td
                  key={c}
                  style={{
                    width: 25,
                    height: 25,
                    border: "1px solid",
                    background:
                      game.snake.some(
                        ([x, y]) => x === r && y === c
                      )
                        ? "green"
                        : game.food[0] === r &&
                          game.food[1] === c
                        ? "red"
                        : "white",
                  }}
                />
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
